    if (!ex.data || ex.data.length === 0) {
      let nombre = null;
      try { const c = await axios.get(SB + '/rest/v1/clientes_chat?select=nombre&telefono=eq.' + encodeURIComponent(telefono), { headers: H }); nombre = (c.data && c.data[0] && c.data[0].nombre) || null; } catch (e) {}
      await axios.post(SB + '/rest/v1/solicitudes_ayuda', { telefono, nombre, consulta, motivo: 'no_encontrado', status: 'pendiente' }, { headers: H });
    }
  }
} catch (e) {}
return [{ json: $json }];

const axios = require('axios');
const https = require('https');

const item = $input.first().json;
const wBody = item.body || {};
const payload = wBody.payload || wBody;
const msgType = (payload.type || '').toLowerCase();
const rawMime = (payload.media && payload.media.mimetype || '').toLowerCase();

const isAudio = payload.hasMedia === true && (rawMime.includes('audio') || msgType === 'ptt' || msgType === 'audio');
const isImage = payload.hasMedia === true && rawMime.includes('image/');

if (!isAudio && !isImage) {
  return [$input.first()];
}

const WAHA_KEY = $env.WAHA_API_KEY;
const OR_KEY = $env.OPENROUTER_API_KEY;
if (!OR_KEY) { return [$input.first()]; }

// Descargar media de WAHA
let mediaBuffer;
let actualMime = rawMime.split(';')[0].trim() || 'application/octet-stream';

if (payload.media && payload.media.url) {
  try {
    const mediaUrl = payload.media.url.replace('http://localhost:3000', 'http://waha_serrucho:3000');
    const resp = await axios.get(mediaUrl, { headers: { 'X-API-Key': WAHA_KEY }, responseType: 'arraybuffer', timeout: 30000 });
    mediaBuffer = Buffer.from(resp.data);
    actualMime = (payload.media.mimetype || actualMime).split(';')[0].trim();
  } catch (e) {}
}

if (!mediaBuffer && payload.body && String(payload.body).startsWith('data:')) {
  try {
    const parts = payload.body.split(',');
    const m = parts[0].split(';')[0].replace('data:', '').trim();
    if (parts[1]) { mediaBuffer = Buffer.from(parts[1], 'base64'); actualMime = m || actualMime; }
  } catch (e) {}
}

if (!mediaBuffer) { return [$input.first()]; }

let resultText = '';

if (isAudio) {
  // === AUDIO: Transcribir con OpenRouter Whisper ===
  let fmt = 'ogg';
  if (actualMime.includes('wav')) fmt = 'wav';
  else if (actualMime.includes('mp3') || actualMime.includes('mpeg')) fmt = 'mp3';
  else if (actualMime.includes('mp4')) fmt = 'mp4';
  else if (actualMime.includes('webm')) fmt = 'webm';
  else if (actualMime.includes('flac')) fmt = 'flac';

  const reqBody = JSON.stringify({ model: 'openai/whisper-large-v3-turbo', input_audio: { data: mediaBuffer.toString('base64'), format: fmt } });

  resultText = await new Promise((resolve) => {
    const req = https.request({
      hostname: 'openrouter.ai', port: 443, path: '/api/v1/audio/transcriptions', method: 'POST',
      headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + OR_KEY, 'Content-Length': Buffer.byteLength(reqBody) }
    }, (res) => {
      const chunks = [];
      res.on('data', c => chunks.push(c));
      res.on('end', () => {
        const t = Buffer.concat(chunks).toString();
        if (res.statusCode === 200) { try { resolve((JSON.parse(t).text || '').trim()); } catch (e) { resolve(t.trim()); } }
        else resolve('');
      });
    });
    req.on('error', () => resolve(''));
    req.setTimeout(60000, () => { req.destroy(); resolve(''); });
    req.write(reqBody);
    req.end();
  });

} else if (isImage) {
  // === IMAGEN: Analizar con gpt-4o-mini via OpenRouter ===
  const dataUrl = 'data:' + actualMime + ';base64,' + mediaBuffer.toString('base64');
  const reqBody = JSON.stringify({
    model: 'openai/gpt-4o-mini',
    max_tokens: 300,
    messages: [{
      role: 'user',
      content: [
        { type: 'text', text: 'Eres el asistente de una ferretería venezolana llamada El Serrucho. Analiza esta imagen. Si muestra un producto de ferretería, construcción, plomería, electricidad o herramientas, identifícalo con nombre, medida y características visibles. Si es una lista de materiales o presupuesto escrito, léela completa. Si es algo diferente, descríbelo brevemente. Responde en español, conciso y directo, máximo 3 oraciones.' },
        { type: 'image_url', image_url: { url: dataUrl } }
      ]
    }]
  });

  const desc = await new Promise((resolve) => {
    const req = https.request({
      hostname: 'openrouter.ai', port: 443, path: '/api/v1/chat/completions', method: 'POST',
      headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + OR_KEY, 'Content-Length': Buffer.byteLength(reqBody) }
    }, (res) => {
      const chunks = [];
      res.on('data', c => chunks.push(c));
      res.on('end', () => {
        const t = Buffer.concat(chunks).toString();
        if (res.statusCode === 200) { try { resolve((JSON.parse(t).choices[0].message.content || '').trim()); } catch (e) { resolve(''); } }
        else resolve('');
      });
    });
    req.on('error', () => resolve(''));
    req.setTimeout(60000, () => { req.destroy(); resolve(''); });
    req.write(reqBody);
    req.end();
  });

  resultText = desc ? '[Imagen del cliente]: ' + desc : '';
}

if (!resultText) { return [$input.first()]; }

const modified = JSON.parse(JSON.stringify(item));
const pld = modified.body.payload || modified.body;
pld.body = resultText;
pld._transcribed = true;
pld._tipo_original = isImage ? 'image' : 'ptt';
return [{ json: modified }];

// Guardia anti-salida-corrupta del agente.
// Si el LLM filtra una tool-call como texto ("Calling xxx_tool with input: ...")
// o entra en un bucle de repetición (degeneración), reemplaza la salida por un
// fallback amable: el cliente NUNCA debe recibir basura interna por WhatsApp.
const FALLBACK = 'Disculpa 🙏, se me enredó un cable procesando eso 👨🏻‍🔧. ¿Me repites qué necesitas (o tu lista de materiales)? Así te lo busco y te armo el presupuesto enseguida 🪚';

function looksCorrupt(text) {
  if (!text || typeof text !== 'string') return false;
  if (text.length > 4000) return true;                              // ninguna respuesta legítima es tan larga
  if (/Calling\s+[\w-]+\s+with input\s*:/i.test(text)) return true; // tool-call filtrada como texto
  if (/"id"\s*:\s*"call_/.test(text)) return true;                  // id de tool_call de OpenAI filtrado
  const head = text.slice(0, 4000);
  if (/(.{1,4})\1{20,}/s.test(head)) return true;                   // bucle: grupo de 1-4 chars repetido 20+ veces
  return false;
}

for (const item of items) {
  const out = item.json ? item.json.output : undefined;
  if (looksCorrupt(out)) {
    console.warn('[Sanitize] salida corrupta del agente -> fallback. Original (200 chars):', String(out).slice(0, 200));
    item.json.output = FALLBACK;
    item.json._sanitized = true;
  }
}
return items;
